exercise.solutionCode:
const numbers = [3, 8, 15, 4, 22, 7, 10, 1, 6];

let sum       = 0;
let evenCount = 0;

for (const num of numbers) {
    sum += num;
    if (num % 2 === 0) {
        evenCount++;
    }
}

console.log("Sum:",        sum);
console.log("Even count:", evenCount);

