const secret   = 42;
const guesses  = [15, 80, 42];
let idx        = 0;
let attempts   = 0;

while (idx < guesses.length) {
    const guess = guesses[idx];
    idx++;
    attempts++;

    if (guess < secret) {
        console.log(`Guess ${guess}: Too low`);
    } else if (guess > secret) {
        console.log(`Guess ${guess}: Too high`);
    } else {
        console.log(`Guess ${guess}: Correct in ${attempts} attempt(s)!`);
        break;
    }
}

